import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';

const STATUS_COLOR = {
  Pending: { bg: '#fef3c7', color: '#92400e' },
  Approved: { bg: '#d1fae5', color: '#065f46' },
  Rejected: { bg: '#fee2e2', color: '#991b1b' },
  Waiting: { bg: '#e0e7ff', color: '#3730a3' },
};

export default function FinanceDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [expenses, setExpenses] = useState([]);
  const [comments, setComments] = useState({});
  const [activeComment, setActiveComment] = useState(null);

  useEffect(() => {
    if (!user) return;
    api.get('/expenses').then((res) => setExpenses(res.data));
  }, [user]);

  const handleAction = async (id, action) => {
    try {
      await api.put(`/expenses/${id}/approve`, { action, comment: comments[id] || '' });
      const res = await api.get('/expenses');
      setExpenses(res.data);
      setActiveComment(null);
    } catch (err) {
      alert(err.response?.data?.message || 'Action failed');
    }
  };

  const pending = expenses.filter((e) =>
    e.status === 'Pending' &&
    e.approvals?.some((a) => {
      const approverId = a.approverId?._id || a.approverId;
      return String(approverId) === String(user?._id) && a.status === 'Pending';
    })
  );

  const roleColor = {
    Finance: { header: '#0ea5e9', light: '#e0f2fe' },
    Director: { header: '#8b5cf6', light: '#ede9fe' },
  };
  const rc = roleColor[user?.role] || roleColor.Finance;

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={{ ...s.header, background: rc.header }}>
        <div>
          <h2 style={{ margin: 0, color: '#fff' }}>{user?.role} Dashboard</h2>
          <span style={{ color: 'rgba(255,255,255,0.85)', fontSize: '0.9rem' }}>
            Welcome, {user?.name}
          </span>
        </div>
        <button style={s.btnLogout} onClick={logout}>Logout</button>
      </div>

      <div style={s.body}>
        {/* Stats */}
        <div style={s.statsRow}>
          <div style={{ ...s.statCard, background: rc.light }}>
            <span style={s.statNum}>{pending.length}</span>
            <span style={s.statLabel}>Awaiting My Approval</span>
          </div>
          <div style={s.statCard}>
            <span style={s.statNum}>
              {expenses.filter((e) => e.status === 'Approved').length}
            </span>
            <span style={s.statLabel}>Approved</span>
          </div>
          <div style={s.statCard}>
            <span style={s.statNum}>
              {expenses.filter((e) => e.status === 'Rejected').length}
            </span>
            <span style={s.statLabel}>Rejected</span>
          </div>
          <div style={s.statCard}>
            <span style={s.statNum}>{expenses.length}</span>
            <span style={s.statLabel}>Total Expenses</span>
          </div>
        </div>

        {/* Pending Approvals */}
        <div style={s.section}>
          <h3 style={s.sectionTitle}>
            Pending Approvals
            {pending.length > 0 && <span style={{ ...s.count, background: rc.header }}>{pending.length}</span>}
          </h3>
          <div style={s.tableWrap}>
            <table style={s.table}>
              <thead>
                <tr style={s.thead}>
                  {['Employee', 'Expense Type', 'Vendor', 'Amount', 'Date', 'Status', 'Action'].map((h) => (
                    <th key={h} style={s.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {pending.length === 0 && (
                  <tr><td colSpan={7} style={s.empty}>No pending approvals</td></tr>
                )}
                {pending.map((e) => (
                  <>
                    <tr key={e._id} style={s.tr}>
                      <td style={s.td}>{e.employee?.name}</td>
                      <td style={s.td}>{e.category}</td>
                      <td style={s.td}>{e.ocrData?.vendor || '—'}</td>
                      <td style={s.td}><strong>{e.currency} {Number(e.amount).toFixed(2)}</strong></td>
                      <td style={s.td}>{new Date(e.date).toLocaleDateString()}</td>
                      <td style={s.td}>
                        <span style={{ ...s.badge, ...STATUS_COLOR[e.status] }}>{e.status}</span>
                      </td>
                      <td style={s.td}>
                        <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap' }}>
                          <button style={s.btnApprove} onClick={() => handleAction(e._id, 'Approved')}>
                            ✓ Approve
                          </button>
                          <button style={s.btnReject} onClick={() => handleAction(e._id, 'Rejected')}>
                            ✕ Reject
                          </button>
                          <button style={s.btnComment}
                            onClick={() => setActiveComment(activeComment === e._id ? null : e._id)}>
                            💬
                          </button>
                          <button style={s.btnView} onClick={() => navigate(`/expenses/${e._id}`)}>
                            View
                          </button>
                        </div>
                      </td>
                    </tr>
                    {activeComment === e._id && (
                      <tr key={`${e._id}-c`}>
                        <td colSpan={7} style={{ padding: '0.5rem 1rem', background: '#f9fafb' }}>
                          <textarea style={s.commentBox}
                            placeholder="Add a comment..."
                            value={comments[e._id] || ''}
                            onChange={(ev) => setComments({ ...comments, [e._id]: ev.target.value })} />
                        </td>
                      </tr>
                    )}
                  </>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* All Expenses */}
        <div style={s.section}>
          <h3 style={s.sectionTitle}>All Expenses</h3>
          <div style={s.tableWrap}>
            <table style={s.table}>
              <thead>
                <tr style={s.thead}>
                  {['Employee', 'Type', 'Amount', 'Date', 'Status', 'Detail'].map((h) => (
                    <th key={h} style={s.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {expenses.map((e) => (
                  <tr key={e._id} style={s.tr}>
                    <td style={s.td}>{e.employee?.name}</td>
                    <td style={s.td}>{e.category}</td>
                    <td style={s.td}>{e.currency} {Number(e.amount).toFixed(2)}</td>
                    <td style={s.td}>{new Date(e.date).toLocaleDateString()}</td>
                    <td style={s.td}>
                      <span style={{ ...s.badge, ...STATUS_COLOR[e.status] }}>{e.status}</span>
                    </td>
                    <td style={s.td}>
                      <button style={s.btnView} onClick={() => navigate(`/expenses/${e._id}`)}>View</button>
                    </td>
                  </tr>
                ))}
                {expenses.length === 0 && (
                  <tr><td colSpan={6} style={s.empty}>No expenses</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

const s = {
  page: { minHeight: '100vh', background: '#f0f2f5', fontFamily: 'sans-serif' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1.25rem 2rem' },
  body: { maxWidth: '1100px', margin: '0 auto', padding: '1.5rem' },
  statsRow: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '1rem', marginBottom: '1.5rem' },
  statCard: { background: '#fff', borderRadius: '8px', padding: '1rem 1.25rem', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', display: 'flex', flexDirection: 'column', gap: '0.2rem' },
  statNum: { fontSize: '1.8rem', fontWeight: 700, color: '#1f2937' },
  statLabel: { fontSize: '0.82rem', color: '#6b7280' },
  section: { marginBottom: '2rem' },
  sectionTitle: { fontSize: '1rem', fontWeight: 700, color: '#374151', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '0.5rem' },
  count: { color: '#fff', borderRadius: '999px', padding: '0.1rem 0.55rem', fontSize: '0.78rem' },
  tableWrap: { background: '#fff', borderRadius: '8px', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', overflow: 'hidden' },
  table: { width: '100%', borderCollapse: 'collapse' },
  thead: { background: '#f9fafb' },
  th: { padding: '0.7rem 1rem', textAlign: 'left', fontSize: '0.78rem', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', borderBottom: '1px solid #e5e7eb' },
  tr: { borderBottom: '1px solid #f3f4f6' },
  td: { padding: '0.7rem 1rem', fontSize: '0.88rem', color: '#374151' },
  empty: { textAlign: 'center', padding: '2rem', color: '#9ca3af' },
  badge: { padding: '0.2rem 0.7rem', borderRadius: '999px', fontSize: '0.78rem', fontWeight: 600 },
  btnApprove: { padding: '0.3rem 0.75rem', background: '#10b981', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '0.82rem', fontWeight: 600 },
  btnReject: { padding: '0.3rem 0.75rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '0.82rem', fontWeight: 600 },
  btnComment: { padding: '0.3rem 0.5rem', background: '#f3f4f6', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  btnView: { padding: '0.3rem 0.75rem', background: '#ede9fe', color: '#4f46e5', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '0.82rem', fontWeight: 600 },
  btnLogout: { padding: '0.45rem 1rem', background: 'rgba(255,255,255,0.2)', color: '#fff', border: '1px solid rgba(255,255,255,0.4)', borderRadius: '6px', cursor: 'pointer' },
  commentBox: { width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '6px', fontSize: '0.88rem', boxSizing: 'border-box', minHeight: '60px' },
};
